arguments.keystrokes:
awk -F'\t' '
$1 >= 10485760 && $2 !~ /\/$/ && $2 != "/var/data" && $2 != "/var/data/logs" && $2 != "/var/data/backups" && $2 != "/var/data/cache" && $2 != "/var/data/cache/thumbnails" && $2 != "/var/data/uploads" && $2 != "/var/data/archives" {
  mb = int($1 / 1048576)
  print mb, $1, $2
}' /home/user/disk_inventory.txt | sort -t' ' -k2,2nr -k3,3 | awk '{print $1"MB " $3}' > /home/user/reports/large_files.txt

awk -F'\t' '
BEGIN { OFS="," }
$2 != "/var/data" && $2 != "/var/data/logs" && $2 != "/var/data/backups" && $2 != "/var/data/cache" && $2 != "/var/data/cache/thumbnails" && $2 != "/var/data/uploads" && $2 != "/var/data/archives" {
  path = $2
  n = split(path, parts, "/")
  filename = parts[n]
  if (match(filename, /\.([^.]+)$/, arr)) {
    ext = tolower(arr[1])
  } else {
    ext = "NO_EXTENSION"
  }
  bytes[ext] += $1
}
END {
  print "extension,total_bytes"
  for (ext in bytes) {
    print ext, bytes[ext]
  }
}' /home/user/disk_inventory.txt | (read header; echo "$header"; sort -t',' -k2,2nr) > /home/user/reports/extension_summary.csv

awk -F'\t' '
$2 != "/var/data" && $2 != "/var/data/logs" && $2 != "/var/data/backups" && $2 != "/var/data/cache" && $2 != "/var/data/cache/thumbnails" && $2 != "/var/data/uploads" && $2 != "/var/data/archives" {
  path = $2
  sub(/^\/var\/data\//, "", path)
  split(path, parts, "/")
  dir = parts[1]
  bytes[dir] += $1
  total += $1
}
END {
  for (dir in bytes) {
    pct = (bytes[dir] / total) * 100
    printf "%s %d %.1f%%\n", dir, bytes[dir], pct
  }
}' /home/user/disk_inventory.txt | sort -t' ' -k2,2nr > /home/user/reports/directory_rollup.txt
